const { chromium } = require('playwright');
const path = require('path');

(async () => {
  const browser = await chromium.launch({ headless: false });
  const context = await browser.newContext({
    viewport: { width: 1920, height: 1080 }
  });
  const page = await context.newPage();

  const screenshotDir = path.join(__dirname, '.storybook', 'screenshots');
  const results = {
    success: [],
    errors: []
  };

  try {
    console.log('Navigating to Storybook...');
    await page.goto('http://localhost:6006', { waitUntil: 'networkidle', timeout: 30000 });
    await page.waitForTimeout(2000);

    // Navigate directly to the Demo story via URL
    console.log('Navigating to SDUI Order Detail Demo story...');
    await page.goto('http://localhost:6006/?path=/story/sdui-order-detail--demo', { waitUntil: 'networkidle' });
    await page.waitForTimeout(3000);

    // Wait for the iframe to load (Storybook renders stories in an iframe)
    const frameElement = await page.frameLocator('#storybook-preview-iframe');

    // Screenshot 1: Demo story (voucher variant - default)
    console.log('Taking screenshot of voucher variant...');
    const fullPage = await frameElement.locator('body').first();
    await fullPage.screenshot({
      path: path.join(screenshotDir, 'sdui-orderdetail-voucher.png'),
    });
    results.success.push('Voucher variant screenshot captured');

    // Click TAG toggle button
    console.log('Looking for TAG toggle button...');
    const tagButton = frameElement.locator('text=TAG').first();
    try {
      await tagButton.click({ timeout: 5000 });
      await page.waitForTimeout(1500);

      // Screenshot 2: TAG variant
      console.log('Taking screenshot of TAG variant...');
      await fullPage.screenshot({
        path: path.join(screenshotDir, 'sdui-orderdetail-tag.png'),
      });
      results.success.push('TAG variant screenshot captured');
    } catch (e) {
      results.errors.push(`TAG toggle button error: ${e.message}`);
    }

    // Click Marketplace toggle button
    console.log('Looking for Marketplace toggle button...');
    const marketplaceButton = frameElement.locator('text=Marketplace').first();
    try {
      await marketplaceButton.click({ timeout: 5000 });
      await page.waitForTimeout(1500);

      // Screenshot 3: Marketplace variant
      console.log('Taking screenshot of Marketplace variant...');
      await fullPage.screenshot({
        path: path.join(screenshotDir, 'sdui-orderdetail-marketplace.png'),
      });
      results.success.push('Marketplace variant screenshot captured');
    } catch (e) {
      results.errors.push(`Marketplace toggle button error: ${e.message}`);
    }

    // Navigate to Side-by-Side Comparison story
    console.log('Navigating to Side-by-Side Comparison story...');
    await page.goto('http://localhost:6006/?path=/story/sdui-order-detail--comparison', { waitUntil: 'networkidle' });
    await page.waitForTimeout(3000);

    // Screenshot 4: Comparison view
    console.log('Taking screenshot of comparison view...');
    const comparisonFrame = await page.frameLocator('#storybook-preview-iframe');
    const comparisonBody = comparisonFrame.locator('body').first();
    await comparisonBody.screenshot({
      path: path.join(screenshotDir, 'sdui-orderdetail-comparison.png'),
    });
    results.success.push('Side-by-Side Comparison screenshot captured');

  } catch (error) {
    results.errors.push(`Error: ${error.message}`);
    console.error('Error during validation:', error);
  } finally {
    await page.waitForTimeout(2000);
    await browser.close();

    // Print results
    console.log('\n=== VALIDATION RESULTS ===');
    console.log('\nSuccesses:');
    results.success.forEach(msg => console.log(`  ✓ ${msg}`));

    if (results.errors.length > 0) {
      console.log('\nErrors:');
      results.errors.forEach(msg => console.log(`  ✗ ${msg}`));
    }

    console.log('\n=========================\n');
  }
})();

